  styles: [".modern-footer[_ngcontent-%COMP%] {\r\n    position: relative;\r\n    background: linear-gradient(135deg, #1e3a8a 0%, #667eea 50%, #764ba2 100%);\r\n    color: white;\r\n    margin-top: 80px;\r\n    overflow: hidden;\r\n}\r\n\r\n.footer-wave[_ngcontent-%COMP%] {\r\n    position: absolute;\r\n    top: -1px;\r\n    left: 0;\r\n    width: 100%;\r\n    overflow: hidden;\r\n    line-height: 0;\r\n}\r\n\r\n.footer-wave[_ngcontent-%COMP%]   svg[_ngcontent-%COMP%] {\r\n    position: relative;\r\n    display: block;\r\n    width: calc(100% + 1.3px);\r\n    height: 120px;\r\n}\r\n\r\n.footer-content[_ngcontent-%COMP%] {\r\n    position: relative;\r\n    max-width: 1400px;\r\n    margin: 0 auto;\r\n    padding: 80px 40px 30px;\r\n}\r\n\r\n.footer-grid[_ngcontent-%COMP%] {\r\n    display: grid;\r\n    grid-template-columns: 2fr 1fr 1fr 1.5fr;\r\n    gap: 50px;\r\n    margin-bottom: 50px;\r\n}\r\n\r\n.footer-column[_ngcontent-%COMP%] {\r\n    animation: _ngcontent-%COMP%_fadeInUp 0.8s ease-out;\r\n}\r\n\r\n.footer-logo[_ngcontent-%COMP%] {\r\n    font-size: 2rem;\r\n    font-weight: 800;\r\n    margin-bottom: 15px;\r\n    background: linear-gradient(135deg, #fff 0%, #e0e7ff 100%);\r\n    -webkit-background-clip: text;\r\n    -webkit-text-fill-color: transparent;\r\n    background-clip: text;\r\n}\r\n\r\n.footer-tagline[_ngcontent-%COMP%] {\r\n    font-size: 0.95rem;\r\n    line-height: 1.6;\r\n    color: rgba(255, 255, 255, 0.8);\r\n    margin-bottom: 25px;\r\n}\r\n\r\n.social-links[_ngcontent-%COMP%] {\r\n    display: flex;\r\n    gap: 15px;\r\n}\r\n\r\n.social-link[_ngcontent-%COMP%] {\r\n    width: 40px;\r\n    height: 40px;\r\n    border-radius: 50%;\r\n    background: rgba(255, 255, 255, 0.1);\r\n    -webkit-backdrop-filter: blur(10px);\r\n            backdrop-filter: blur(10px);\r\n    display: flex;\r\n    align-items: center;\r\n    justify-content: center;\r\n    color: white;\r\n    text-decoration: none;\r\n    transition: all 0.3s ease;\r\n    border: 1px solid rgba(255, 255, 255, 0.2);\r\n}\r\n\r\n.social-link[_ngcontent-%COMP%]:hover {\r\n    background: rgba(255, 255, 255, 0.2);\r\n    transform: translateY(-3px);\r\n    box-shadow: 0 5px 15px rgba(0, 0, 0, 0.3);\r\n}\r\n\r\n.footer-heading[_ngcontent-%COMP%] {\r\n    font-size: 1.2rem;\r\n    font-weight: 700;\r\n    margin-bottom: 20px;\r\n    color: white;\r\n    position: relative;\r\n    padding-bottom: 10px;\r\n}\r\n\r\n.footer-heading[_ngcontent-%COMP%]::after {\r\n    content: '';\r\n    position: absolute;\r\n    bottom: 0;\r\n    left: 0;\r\n    width: 40px;\r\n    height: 3px;\r\n    background: linear-gradient(90deg, rgba(255, 255, 255, 0.8) 0%, transparent 100%);\r\n    border-radius: 2px;\r\n}\r\n\r\n.footer-links[_ngcontent-%COMP%] {\r\n    list-style: none;\r\n    padding: 0;\r\n    margin: 0;\r\n}\r\n\r\n.footer-links[_ngcontent-%COMP%]   li[_ngcontent-%COMP%] {\r\n    margin-bottom: 12px;\r\n}\r\n\r\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%] {\r\n    color: rgba(255, 255, 255, 0.8);\r\n    text-decoration: none;\r\n    font-size: 0.95rem;\r\n    transition: all 0.3s ease;\r\n    display: inline-block;\r\n}\r\n\r\n.footer-links[_ngcontent-%COMP%]   a[_ngcontent-%COMP%]:hover {\r\n    color: white;\r\n    transform: translateX(5px);\r\n}\r\n\r\n.footer-contact[_ngcontent-%COMP%] {\r\n    list-style: none;\r\n    padding: 0;\r\n    margin: 0;\r\n}\r\n\r\n.footer-contact[_ngcontent-%COMP%]   li[_ngcontent-%COMP%] {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 12px;\r\n    margin-bottom: 15px;\r\n    color: rgba(255, 255, 255, 0.8);\r\n    font-size: 0.95rem;\r\n}\r\n\r\n.footer-contact[_ngcontent-%COMP%]   svg[_ngcontent-%COMP%] {\r\n    flex-shrink: 0;\r\n    opacity: 0.8;\r\n}\r\n\r\n.footer-bottom[_ngcontent-%COMP%] {\r\n    border-top: 1px solid rgba(255, 255, 255, 0.1);\r\n    padding-top: 30px;\r\n    display: flex;\r\n    justify-content: space-between;\r\n    align-items: center;\r\n    flex-wrap: wrap;\r\n    gap: 20px;\r\n}\r\n\r\n.copyright[_ngcontent-%COMP%] {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 8px;\r\n    color: rgba(255, 255, 255, 0.7);\r\n    font-size: 0.9rem;\r\n}\r\n\r\n.footer-credits[_ngcontent-%COMP%] {\r\n    display: flex;\r\n    align-items: center;\r\n    gap: 6px;\r\n    color: rgba(255, 255, 255, 0.7);\r\n    font-size: 0.9rem;\r\n}\r\n\r\n.heart-icon[_ngcontent-%COMP%] {\r\n    color: #ff6b9d;\r\n    animation: _ngcontent-%COMP%_heartbeat 1.5s ease-in-out infinite;\r\n}\r\n\r\n@keyframes _ngcontent-%COMP%_fadeInUp {\r\n    from {\r\n        opacity: 0;\r\n        transform: translateY(30px);\r\n    }\r\n    to {\r\n        opacity: 1;\r\n        transform: translateY(0);\r\n    }\r\n}\r\n\r\n@keyframes _ngcontent-%COMP%_heartbeat {\r\n    0%, 100% {\r\n        transform: scale(1);\r\n    }\r\n    10%, 30% {\r\n        transform: scale(1.2);\r\n    }\r\n    20%, 40% {\r\n        transform: scale(1);\r\n    }\r\n}\r\n\r\n\r\n@media (max-width: 1024px) {\r\n    .footer-grid[_ngcontent-%COMP%] {\r\n        grid-template-columns: 1fr 1fr;\r\n        gap: 40px;\r\n    }\r\n}\r\n\r\n@media (max-width: 768px) {\r\n    .footer-content[_ngcontent-%COMP%] {\r\n        padding: 60px 20px 20px;\r\n    }\r\n    \r\n    .footer-grid[_ngcontent-%COMP%] {\r\n        grid-template-columns: 1fr;\r\n        gap: 35px;\r\n    }\r\n    \r\n    .footer-bottom[_ngcontent-%COMP%] {\r\n        flex-direction: column;\r\n        text-align: center;\r\n    }\r\n    \r\n    .social-links[_ngcontent-%COMP%] {\r\n        justify-content: center;\r\n    }\r\n}\n/*# sourceMappingURL=data:application/json;charset=utf-8;base64, */"]
